+/* Table controls toolbar */
+.bv-table-controls {
+    display: flex;
+    align-items: center;
+    gap: 0.35em;
+    margin-top: 0.5em;
+    margin-bottom: 0.25em;
+    opacity: 0;
+    transition: opacity var(--bv-transition);
