+/* Show on hover (desktop) */
+.prose table.bv-table:hover + .bv-table-controls,
+.bv-table-controls:hover,
+.prose > *:has(+ table.bv-table):hover ~ .bv-table-controls {
+    opacity: 1;
+}
+
+/* Reverse order: toolbar is injected BEFORE the table */
+.bv-table-controls:has(+ table.bv-table:hover),
